/// <summary>
/// 为 Transoceanic 系列源生成器提供通用辅助方法、常量和扩展。
/// 该类型中的所有成员均为静态成员，可在源生成器的初始化与执行阶段复用。
/// </summary>
internal static class SourceGeneratorHelper
{
    /// <summary>
    /// 标准文件头。包含自动生成标识、开发者说明、必要的警告禁用等。
    /// </summary>
    public const string FileHeader =
    """
        // <auto-generated/>
        // Developed by ColdsUx

        #pragma warning disable CS0106
        #pragma warning disable CS0109
        #pragma warning disable CS1591

        """;

    /// <summary>
    /// 用于标记永远不会出现在编辑器浏览列表中的特性字符串。
    /// 等价于 <c>[global::System.ComponentModel.EditorBrowsable(global::System.ComponentModel.EditorBrowsableState.Never)]</c>。
    /// </summary>
    public const string NeverBrowsableIdentifier = "[global::System.ComponentModel.EditorBrowsable(global::System.ComponentModel.EditorBrowsableState.Never)]";

    /// <summary>
    /// 外部特性命名空间的前缀，便于在生成的代码中统一引用。
    /// 例如：<c>global::Transoceanic.Framework.ExternalAttributes.SomeAttribute</c>。
    /// </summary>
    public const string ExternalAttributePrefix = "global::Transoceanic.Framework.ExternalAttributes.";

    /// <summary>
    /// 当前代码辅助库的版本号，主要用于 <see cref="GetGeneratedCodeMarker"/> 生成的标记特性。
    /// </summary>
    public const string Version = "1.0.0.0";

    /// <summary>
    /// 生成一个带有 <see cref="System.CodeDom.Compiler.GeneratedCodeAttribute"/> 特性的字符串，
    /// 用于标记生成的代码来自指定的源生成器。
    /// </summary>
    /// <param name="generatorName">源生成器的名称，会拼接到特性构造函数参数的 "TransoceanicCodeAssist." 之后。</param>
    /// <returns>格式化的特性字符串，例如：<c>[global::System.CodeDom.Compiler.GeneratedCode("TransoceanicCodeAssist.MyGen", "1.0.0.0")]</c>。</returns>
    public static string GetGeneratedCodeMarker(string generatorName) => $"""[global::System.CodeDom.Compiler.GeneratedCode("TransoceanicCodeAssist.{generatorName}", "{Version}")]""";

    /// <summary>
    /// 获取解决方案中所有类型声明语法的增量值提供程序。
    /// 可用于后续筛选出 <see langword="partial"/> 类型等。
    /// </summary>
    /// <param name="context">增量生成器初始化上下文。</param>
    /// <returns>提供 <see cref="Microsoft.CodeAnalysis.CSharp.Syntax.TypeDeclarationSyntax"/> 节点的增量值序列。</returns>
    public static IncrementalValuesProvider<TypeDeclarationSyntax> GetTypeDeclarations(IncrementalGeneratorInitializationContext context) =>
        context.SyntaxProvider.CreateSyntaxProvider(
            predicate: (node, _) => node is TypeDeclarationSyntax,
            transform: (ctx, _) => (TypeDeclarationSyntax)ctx.Node
        );

    /// <summary>
    /// 尝试从类型声明语法和编译的组合中获取 <see cref="INamedTypeSymbol"/>，要求该类型声明包含 <see langword="partial"/> 关键字。
    /// </summary>
    /// <param name="tuple">包含类型声明语法（左）和编译（右）的元组。</param>
    /// <param name="symbol">当方法返回 <see langword="true"/> 时，表示找到的命名类型符号；否则为 <see langword="null"/>。</param>
    /// <returns>如果类型声明是分部类型且能获取到符号，则返回 <see langword="true"/>；否则返回 <see langword="false"/>。</returns>
    public static bool TryGetPartialTypeSymbolInfo((TypeDeclarationSyntax Left, Compilation Right) tuple, out INamedTypeSymbol symbol)
    {
        TypeDeclarationSyntax typeDecl = tuple.Left;
        Compilation compilation = tuple.Right;

        if (typeDecl.Modifiers.Any(SyntaxKind.PartialKeyword))
        {
            SemanticModel model = compilation.GetSemanticModel(typeDecl.SyntaxTree);
            if (model.GetDeclaredSymbol(typeDecl) is INamedTypeSymbol typeSymbol)
            {
                symbol = typeSymbol;
                return true;
            }
        }

        symbol = null;
        return false;
    }

    /// <summary>
    /// 获取解决方案中所有方法声明语法的增量值提供程序。
    /// </summary>
    /// <param name="context">增量生成器初始化上下文。</param>
    /// <returns>提供 <see cref="Microsoft.CodeAnalysis.CSharp.Syntax.MethodDeclarationSyntax"/> 节点的增量值序列。</returns>
    public static IncrementalValuesProvider<MethodDeclarationSyntax> GetMethodDeclarations(IncrementalGeneratorInitializationContext context) =>
        context.SyntaxProvider.CreateSyntaxProvider(
            predicate: (node, _) => node is MethodDeclarationSyntax,
            transform: (ctx, _) => (MethodDeclarationSyntax)ctx.Node
        );

    /// <summary>
    /// 尝试从方法声明语法和编译的组合中获取 <see cref="IMethodSymbol"/>，要求该方法声明包含 <see langword="partial"/> 关键字。
    /// </summary>
    /// <param name="tuple">包含方法声明语法（左）和编译（右）的元组。</param>
    /// <param name="symbol">当方法返回 <see langword="true"/> 时，表示找到的方法符号；否则为 <see langword="null"/>。</param>
    /// <returns>如果方法声明是分部方法且能获取到符号，则返回 <see langword="true"/>；否则返回 <see langword="false"/>。</returns>
    public static bool TryGetPartialMethodSymbolInfo((MethodDeclarationSyntax Left, Compilation Right) tuple, out IMethodSymbol symbol)
    {
        MethodDeclarationSyntax methodDecl = tuple.Left;
        Compilation compilation = tuple.Right;

        if (methodDecl.Modifiers.Any(SyntaxKind.PartialKeyword))
        {
            SemanticModel model = compilation.GetSemanticModel(methodDecl.SyntaxTree);
            if (model.GetDeclaredSymbol(methodDecl) is IMethodSymbol methodSymbol)
            {
                symbol = methodSymbol;
                return true;
